use sdl3::event::Event;
use sdl3::gamepad::Button;
use sdl3::keyboard::Keycode;
use sdl3::pixels::Color;
use std::fs::File;
use std::io::Write;
use std::time::{Duration, Instant};

const CONFIG_PATH: &str = "/var/data/input.conf";
const PROFILE_PATH: &str = "/etc/profile.d/input_wizard.sh";

struct ButtonPrompt {
    name: &'static str,
    sdl_btn: &'static str,
}

impl ButtonPrompt {
    fn new(name: &'static str, sdl_btn: &'static str) -> Self {
        Self { name, sdl_btn }
    }
}

fn write_config(guid_str: &str, mapping: &str) -> std::io::Result<()> {
    let mut f = File::create(CONFIG_PATH)?;
    writeln!(f, "# Input mapping generated by input-wizard")?;
    writeln!(f, "SDL_GAMECONTROLLERCONFIG=\"{},{},{}\"", guid_str, "input-wizard", mapping)?;
    Ok(())
}

fn write_profile(config: &str) -> std::io::Result<()> {
    let mut f = File::create(PROFILE_PATH)?;
    writeln!(f, "#!/bin/sh")?;
    writeln!(f, "export SDL_GAMECONTROLLERCONFIG=\"{}\"", config)?;
    Ok(())
}

fn button_to_string(btn: Button) -> &'static str {
    match btn {
        Button::South => "a",
        Button::East => "b",
        Button::West => "x",
        Button::North => "y",
        Button::Back => "select",
        Button::Start => "start",
        Button::LeftStick => "leftstick",
        Button::RightStick => "rightstick",
        Button::LeftShoulder => "leftshoulder",
        Button::RightShoulder => "rightshoulder",
        Button::DPadUp => "dpup",
        Button::DPadDown => "dpdown",
        Button::DPadLeft => "dpleft",
        Button::DPadRight => "dpright",
        _ => "unknown",
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let sdl_context = sdl3::init()?;
    let video_subsystem = sdl_context.video()?;
    let gamepad_subsystem = sdl_context.gamepad()?;

    let window = video_subsystem
        .window("Input Mapping Wizard", 640, 480)
        .position_centered()
        .build()?;

    let mut canvas = window.into_canvas();
    let mut event_pump = sdl_context.event_pump()?;

    let prompts = vec![
        ButtonPrompt::new("Up", "a"),
        ButtonPrompt::new("Down", "b"),
        ButtonPrompt::new("Left", "x"),
        ButtonPrompt::new("Right", "y"),
        ButtonPrompt::new("Select", "back"),
        ButtonPrompt::new("Start", "start"),
        ButtonPrompt::new("Service", "leftstick"),
        ButtonPrompt::new("Coin", "rightstick"),
    ];

    let num_joys = gamepad_subsystem.num_joysticks()?;
    if num_joys < 1 {
        eprintln!("No game controllers found. Exiting.");
        return Ok(());
    }

    println!("Found {} controller(s)", num_joys);

    let gamepad = match gamepad_subsystem.open(0) {
        Ok(g) => g,
        Err(e) => {
            eprintln!("Could not open gamepad: {}", e);
            return Ok(());
        }
    };

let guid = gamepad.guid();
     let guid_str = guid.to_string();

    println!("\n=== Input Mapping Wizard ===");
    println!("Controller: {}", gamepad.name()?);
    println!("GUID: {}\n", guid_str);

    println!("Press the buttons when prompted. Press ESC to skip.\n");

    let mut mapping = String::new();
    let mut current_prompt = 0;
    let mut waiting_for_input = true;

    while waiting_for_input && current_prompt < prompts.len() {
        print!("Press button for {}: ", prompts[current_prompt].name);
        let _ = std::io::Write::flush(&mut std::io::stdout());

        let start_time = Instant::now();
        let timeout = Duration::from_secs(30);
        let mut button_pressed = false;

        while !button_pressed && start_time.elapsed() < timeout {
            for event in event_pump.poll_iter() {
                match event {
                    Event::ControllerButtonDown { button, .. } => {
let btn_str = button_to_string(button);
                         println!("{}", btn_str);
                         if !mapping.is_empty() {
                             mapping.push(',');
                         }
                         mapping.push_str(&format!("{}:{}", prompts[current_prompt].name, prompts[current_prompt].sdl_btn));
                        button_pressed = true;
                    }
                    Event::KeyDown {
                        keycode: Some(Keycode::Escape),
                        ..
                    } => {
                        println!("(skipped)");
                        button_pressed = true;
                        waiting_for_input = false;
                    }
                    _ => {}
                }
            }

            canvas.set_draw_color(Color::RGB(15, 15, 25));
            canvas.clear();

            canvas.set_draw_color(Color::RGB(255, 215, 0));
            // Draw prompt text would go here in a full implementation

            canvas.present();
            std::thread::sleep(Duration::from_millis(16));
        }

        if !button_pressed {
            println!("(timed out)");
        }
        current_prompt += 1;
    }

// No hardcoded buttons needed - mapping is built from actual button presses

    println!("\nFinal mapping: {}", mapping);
    write_config(&guid_str, &mapping)?;
    write_profile(&mapping)?;

    println!("\nConfiguration saved to {}", CONFIG_PATH);
    println!("Profile saved to {}", PROFILE_PATH);

    Ok(())
}
